  hasDark = await page.evaluate(() => document.documentElement.classList.contains('dark'));
  if (hasDark) pass('Theme toggle switches to dark');
  else fail('Theme toggle to dark', 'dark class not added');

  // Check localStorage
  const stored = await page.evaluate(() => localStorage.theme);
  if (stored === 'dark') pass('Theme persists in localStorage');
  else fail('Theme localStorage', `Got: ${stored}`);

  // Toggle back
  await page.click('#theme-toggle');
  hasDark = await page.evaluate(() => document.documentElement.classList.contains('dark'));
  if (!hasDark) pass('Theme toggle switches back to light');
  else fail('Theme toggle back to light', 'dark class still present');

  // Test 3: Mobile menu
  await page.setViewportSize({ width: 375, height: 812 });
  const hamburgerVisible = await page.isVisible('#mobile-menu-toggle');
  if (hamburgerVisible) pass('Mobile hamburger visible at 375px');
  else fail('Mobile hamburger', 'Not visible');

  await page.click('#mobile-menu-toggle');
  const menuVisible = await page.isVisible('#mobile-menu');
  if (menuVisible) pass('Mobile menu opens');
  else fail('Mobile menu open', 'Not visible');

  await page.click('#mobile-menu-close');
  await page.waitForTimeout(300);
  const menuHidden = await page.evaluate(() => document.getElementById('mobile-menu').classList.contains('hidden'));
  if (menuHidden) pass('Mobile menu closes');
  else fail('Mobile menu close', 'Still visible');

  // Test 4: Tab switching (desktop)
  await page.setViewportSize({ width: 1280, height: 800 });

  // Click voice tab
  const voiceTab = page.locator('[data-tab-trigger="voice"]');
  if (await voiceTab.count() > 0) {
    await voiceTab.click();
    const voicePanel = page.locator('[data-tab-panel="voice"]');
    const voiceVisible = await voicePanel.isVisible();
    const chatPanel = page.locator('[data-tab-panel="chat"]');
    const chatHidden = !(await chatPanel.isVisible());
    if (voiceVisible && chatHidden) pass('Tab switching works (voice tab)');
    else fail('Tab switching', `voice visible=${voiceVisible}, chat hidden=${chatHidden}`);
  } else {
    fail('Tab switching', 'Voice tab trigger not found');
  }

  // Test 5: Mobile accordion
  await page.setViewportSize({ width: 375, height: 812 });
  const accordionItems = page.locator('#features details');
  const accordionCount = await accordionItems.count();
  if (accordionCount === 3) pass('Mobile accordion has 3 items');
  else fail('Mobile accordion', `Found ${accordionCount} items`);

  // Test 6: Smooth scroll link exists
  const demoLink = page.locator('a[href="#demo-widget"]');
  if (await demoLink.count() > 0) pass('Demo widget scroll link exists');
  else fail('Demo widget link', 'Not found');

  // Test 7: External links
  await page.setViewportSize({ width: 1280, height: 800 });

  const githubLink = page.locator('a[href*="github.com/ravencloak-org"]');
  if (await githubLink.count() > 0) pass('GitHub link present');
  else fail('GitHub link', 'Not found');

  const appLinks = page.locator('a[href*="app.ravencloak.org"]');
  const appLinkCount = await appLinks.count();
  if (appLinkCount >= 2) pass(`App links present (${appLinkCount} found)`);
  else fail('App links', `Only ${appLinkCount} found`);

  // Test 8: Key sections exist
  const sections = ['hero', 'problem', 'features', 'how-it-works', 'deploy', 'enterprise', 'pricing', 'cta'];
  let allSections = true;
  for (const id of sections) {
    const el = page.locator(`#${id}`);
    if (await el.count() === 0) { allSections = false; fail(`Section #${id}`, 'Not found'); }
  }
  if (allSections) pass('All 8 content sections present');

  // Test 9: Pricing tiers
  const pricingCards = page.locator('#pricing .rounded-2xl, #pricing .rounded-xl').filter({ has: page.locator('h3') });
  const freeText = await page.locator('#pricing').textContent();
  if (freeText.includes('$0') && freeText.includes('$29') && freeText.includes('Contact Sales'))
    pass('All 3 pricing tiers present');
  else
    fail('Pricing tiers', 'Missing tier data');

  // Test 10: Footer
  const footer = page.locator('#footer');
  if (await footer.count() > 0) {
    const footerText = await footer.textContent();
    if (footerText.includes('Ravencloak') && footerText.includes('MIT License')) pass('Footer present with copyright');
    else fail('Footer content', 'Missing expected text');
  } else {
    fail('Footer', 'Not found');
  }

  // Test 11: Accessibility - skip link
  const skipLink = page.locator('a[href="#main-content"]');
  if (await skipLink.count() > 0) pass('Skip-to-content link present');
  else fail('Skip link', 'Not found');

  // Test 12: Aria labels on sections
  const ariaLabels = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('section[aria-label], nav[id], footer[aria-label]')).length;
  });
  if (ariaLabels >= 8) pass(`Aria labels present (${ariaLabels} elements)`);
  else fail('Aria labels', `Only ${ariaLabels} found`);

  // Test 13: Console errors
  const errors = [];
  page.on('console', msg => { if (msg.type() === 'error') errors.push(msg.text()); });
  await page.reload({ waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(1000);
  if (errors.length === 0) pass('No console errors');
  else fail('Console errors', errors.join('; '));

} catch (e) {
  fail('Unexpected error', e.message);
}

await browser.close();

console.log('\n=== LANDING PAGE TEST RESULTS ===\n');
results.forEach(r => console.log(r));
const passes = results.filter(r => r.startsWith('PASS')).length;
const fails = results.filter(r => r.startsWith('FAIL')).length;
console.log(`\n${passes} passed, ${fails} failed out of ${results.length} tests`);

